const data   = $input.first().json;
const issues = data.issues || [];
const today  = new Date().toLocaleString('es-CL', { timeZone: 'America/Santiago' });
const date   = new Date().toISOString().split('T')[0];

const priorityColors = {
  Highest: { bg: '#fee2e2', color: '#b91c1c', icon: '🔴' },
  High:    { bg: '#fee2e2', color: '#b91c1c', icon: '🔴' },
  Medium:  { bg: '#fef9c3', color: '#854d0e', icon: '🟡' },
  Low:     { bg: '#dcfce7', color: '#166534', icon: '🟢' },
  Lowest:  { bg: '#dcfce7', color: '#166534', icon: '🟢' },
};

const statusColors = {
  'To Do':       { bg: '#f3f4f6', color: '#374151' },
  'In Progress': { bg: '#dbeafe', color: '#1d4ed8' },
  'In Review':   { bg: '#fef9c3', color: '#854d0e' },
  'Done':        { bg: '#dcfce7', color: '#166534' },
};

const bugs    = issues.filter(i => i.fields?.issuetype?.name === 'Bug');
const tasks   = issues.filter(i => i.fields?.issuetype?.name === 'Task');
const stories = issues.filter(i => i.fields?.issuetype?.name === 'Story');

function buildRows(items) {
  return items.map(issue => {
    const f          = issue.fields || {};
    const priority   = f.priority?.name || 'Medium';
    const status     = f.status?.name   || '';
    const resolution = f.resolution?.name || 'Sin resolver';
    const assignee   = f.assignee?.displayName || 'Sin asignar';
    const updated    = (f.updated || '').substring(0, 10);
    const url        = `https://qaprocess1.atlassian.net/browse/${issue.key}`;
    const summary    = (f.summary || '').substring(0, 75);
    const pc = priorityColors[priority] || { bg: '#f4f5f7', color: '#42526e', icon: '⚪' };
    const sc = statusColors[status]     || { bg: '#f3f4f6', color: '#374151' };
    return `<tr>
      <td style="border:1px solid #e5e7eb;padding:8px 10px;font-weight:700;white-space:nowrap">
        <a href="${url}" style="color:#1d4ed8;text-decoration:none">${issue.key}</a>
        <div style="font-size:11px;color:#6b7280;font-weight:400;max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${summary}</div>
      </td>
      <td style="border:1px solid #e5e7eb;padding:8px 10px;font-size:12px">${assignee}</td>
      <td style="border:1px solid #e5e7eb;padding:8px 10px;text-align:center">
        <span style="background:${pc.bg};color:${pc.color};padding:2px 8px;border-radius:12px;font-size:11px;font-weight:700">${pc.icon} ${priority}</span>
      </td>
      <td style="border:1px solid #e5e7eb;padding:8px 10px;text-align:center">
        <span style="background:${sc.bg};color:${sc.color};padding:2px 8px;border-radius:12px;font-size:11px;font-weight:600">${status}</span>
      </td>
      <td style="border:1px solid #e5e7eb;padding:8px 10px;font-size:12px;text-align:center;color:#6b7280">${resolution}</td>
      <td style="border:1px solid #e5e7eb;padding:8px 10px;font-size:12px;text-align:center;color:#6b7280">${updated}</td>
    </tr>`;
  }).join('');
}

function buildSection(title, icon, items, headerBg) {
  if (!items.length) return '';
  return `
    <h3 style="margin:20px 0 8px;font-size:14px;color:${headerBg}">${icon} ${title} (${items.length})</h3>
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-bottom:16px">
      <tr style="background:${headerBg};color:#fff">
        <th style="padding:9px 12px;border:1px solid #e5e7eb;text-align:left;font-size:12px">Work</th>
        <th style="padding:9px 12px;border:1px solid #e5e7eb;text-align:left;font-size:12px">Assignee</th>
        <th style="padding:9px 12px;border:1px solid #e5e7eb;text-align:center;font-size:12px">Priority</th>
        <th style="padding:9px 12px;border:1px solid #e5e7eb;text-align:center;font-size:12px">Status</th>
        <th style="padding:9px 12px;border:1px solid #e5e7eb;text-align:center;font-size:12px">Resolution</th>
        <th style="padding:9px 12px;border:1px solid #e5e7eb;text-align:center;font-size:12px">Updated</th>
      </tr>
      ${buildRows(items)}
    </table>`;
}

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f8fafc;font-family:Arial,sans-serif">
<div style="max-width:820px;margin:0 auto;padding:24px 16px">
  <div style="background:linear-gradient(135deg,#1e3a5f,#2563eb);color:#fff;padding:20px 24px;border-radius:10px 10px 0 0">
    <h2 style="margin:0;font-size:20px">📊 Estatus Diario QA — Proyecto KAN</h2>
    <p style="margin:6px 0 0;font-size:13px;opacity:.85">${today} | Total activos: ${issues.length}</p>
  </div>
  <div style="background:#fff;border:1px solid #e5e7eb;border-top:none;padding:24px;border-radius:0 0 10px 10px">
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:24px">
      <div style="background:#fee2e2;border-radius:8px;padding:14px;text-align:center">
        <div style="font-size:28px;font-weight:700;color:#b91c1c">${bugs.length}</div>
        <div style="font-size:11px;color:#991b1b;margin-top:4px">🐛 BUGS</div>
      </div>
      <div style="background:#dbeafe;border-radius:8px;padding:14px;text-align:center">
        <div style="font-size:28px;font-weight:700;color:#1d4ed8">${tasks.length}</div>
        <div style="font-size:11px;color:#1e40af;margin-top:4px">📋 TASKS</div>
      </div>
      <div style="background:#f3e8ff;border-radius:8px;padding:14px;text-align:center">
        <div style="font-size:28px;font-weight:700;color:#7c3aed">${stories.length}</div>
        <div style="font-size:11px;color:#6d28d9;margin-top:4px">📖 STORIES</div>
      </div>
    </div>
    ${buildSection('Bugs', '🐛', bugs, '#b91c1c')}
    ${buildSection('Tasks', '📋', tasks, '#1d4ed8')}
    ${buildSection('Stories', '📖', stories, '#7c3aed')}
    <p style="margin-top:20px;font-size:11px;color:#9ca3af;text-align:center">
      Reporte automático generado a las 18:00 hs | <a href="https://qaprocess1.atlassian.net" style="color:#6b7280">qaprocess1.atlassian.net</a>
    </p>
  </div>
</div></body></html>`;

return [{
  json: {
    to: 'jaimeqv.2609@gmail.com,javi.gajardo26@gmail.com',
    subject: `📊 Estatus QA Diario KAN — ${bugs.length} Bugs | ${tasks.length} Tasks | ${stories.length} Stories | ${date}`,
    html
  }
}];

